<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Admin\Content\RefinementStatModifierContentService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\StoreRefinementStatModifierRequest;use App\Http\Requests\Admin\Content\UpdateRefinementStatModifierRequest;use App\Models\RefinementStatModifier;use InvalidArgumentException;
final class RefinementStatModifierController extends Controller{public function store(StoreRefinementStatModifierRequest $r,RefinementStatModifierContentService $s){return$this->run(function()use($r,$s){$s->save($r->validated());},'Modificador estadístico actualizado correctamente.');}public function update(UpdateRefinementStatModifierRequest $r,RefinementStatModifier $modifier,RefinementStatModifierContentService $s){return$this->run(function()use($r,$s,$modifier){$s->save($r->validated(),$modifier);},'Modificador estadístico actualizado correctamente.');}public function activate(RefinementStatModifier $modifier,RefinementStatModifierContentService $s){return$this->run(function()use($s,$modifier){$s->activate($modifier);},'Modificador estadístico activado correctamente.');}public function deactivate(RefinementStatModifier $modifier,RefinementStatModifierContentService $s){$s->deactivate($modifier);return back()->with('status','Modificador estadístico desactivado correctamente.');}private function run($operation,$message){try{$operation();return back()->with('status',$message);}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['stat_modifier'=>$e->getMessage()]);}}}
